/**
	 * Fills and returns the product context_data array to be used in filters.
	 *
	 * @param array $context_data The context data for this filter.
	 * @return array
	 */
function product_filter_context_data( array $context_data = array() ): array {
		if ( ! isset( $context_data['product'] ) ) {
			$context_data['product'] = wc_get_product();
		}
		if ( ! $context_data['product'] ) {
			return array();
		}
		if ( ! isset( $context_data['order_total'] ) && ( $context_data['product'] instanceof WC_Product ) ) {
			$context_data['order_total'] = (float) $context_data['product']->get_price( 'raw' );
		}

		return $context_data;
	}

function get_totalauthors($display = true) {
    global $wpdb;
    $totalauthors = (int) $wpdb->get_var("SELECT COUNT(ID) FROM $wpdb->users LEFT JOIN $wpdb->usermeta ON $wpdb->usermeta.user_id = $wpdb->users.ID WHERE $wpdb->users.user_activation_key = '' AND $wpdb->usermeta.meta_key = '".$wpdb->prefix."user_level' AND (meta_value+0.00) > 1");
