/**
     * Escape a URL
     *
     * @since 1.0.0
     *
     * @param string $url web URL
     *
     * @return string escaped string or empty string if passed string failed to parse
     */
function escapeURL($url)
    {
        return htmlspecialchars($url, ENT_QUOTES, 'UTF-8');
    }

